mapper.select:
SELECT
    s.user_id    AS userId,
    u.username   AS username,
    u.real_name  AS realName,
    COALESCE(s.employee_type, u.employee_type) AS employeeType,
    s.ym         AS ym,
    s.module     AS module,
    s.status     AS status
FROM dept_daily_fill_state s
LEFT JOIN sys_user u
  ON u.tenant_id = s.tenant_id
 AND u.id = s.user_id
WHERE s.tenant_id = #{tenantId}
  AND s.module = #{module}
  AND s.ym = #{ym}

    AND s.dept_id = #{deptId}


    AND s.office_id = #{officeId}


    AND s.employee_type = #{employeeType}


    AND s.status = #{status}


    AND (u.username LIKE CONCAT('%', #{keyword}, '%')
      OR u.real_name LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY s.status ASC, u.real_name ASC, u.username ASC, s.user_id ASC
